# model_utils.py – ModelManager.generate_text()
def generate_text(self, prompt: str, temperature: float = 0.1, max_new_tokens: int = 256) -> str:
    if Config.USE_AZURE_AI:
        return self._generate_azure_curl(prompt, temperature, max_new_tokens)
    # Local Phi-3-mini inference path (transformers)
    inputs = self.tokenizer(prompt, return_tensors="pt", truncation=True, max_length=3072)
    with torch.no_grad():
        output = self.model.generate(**inputs, max_new_tokens=max_new_tokens, ...)
    return self.tokenizer.decode(output[0][inputs['input_ids'].shape[1]:], skip_special_tokens=True).strip()
